def add(category, file, title, subtitle, colors, central, panels, process, conditions, composition, accuracy, about=None):
    SPECS.append(
        {
            "category": category,
            "file": file,
            "about": about or title,
            "title": title,
            "subtitle": subtitle,
            "colors": colors,
            "central": central,
            "panels": panels,
            "process": process,
            "conditions": conditions,
            "composition": composition,
            "accuracy": accuracy,
        }
    )


